The reference solution of that problem in Typescript is 
function solve(c: number, connections: number[][], queries: number[][]): number[] {
    // DSU setup
    const parent = new Array(c + 1).fill(0).map((_, i) => i);

    function find(u: number): number {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u: number, v: number) {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU !== rootV) {
            parent[rootV] = rootU;
        }
    }

    // Build DSU
    for (const [u, v] of connections) {
        union(u, v);
    }

    // Group nodes by root
    const componentData = new Map<number, { sortedNodes: number[], minOnline: number }>();

    for (let node = 1; node <= c; node++) {
        const root = find(node);
        if (!componentData.has(root)) {
            componentData.set(root, { sortedNodes: [], minOnline: -1 });
        }
        componentData.get(root)!.sortedNodes.push(node);
    }

    // Sort each component's nodes and set minOnline
    for (const [root, data] of componentData.entries()) {
        data.sortedNodes.sort((a, b) => a - b);
        data.minOnline = data.sortedNodes[0];
    }

    // Initialize online array
    const online = new Array(c + 1).fill(true);

    // Process queries
    const result: number[] = [];

    for (const [type, x] of queries) {
        if (type === 1) {
            if (online[x]) {
                result.push(x);
            } else {
                const root = find(x);
                const comp = componentData.get(root)!;
                if (comp.minOnline !== -1) {
                    result.push(comp.minOnline);
                } else {
                    result.push(-1);
                }
            }
        } else {
            // type 2: offline
            online[x] = false;
            const root = find(x);
            const comp = componentData.get(root)!;
            if (comp.minOnline === x) {
                // Need to find new minOnline
                let newMin = -1;
                for (const node of comp.sortedNodes) {
                    if (online[node]) {
                        newMin = node;
                        break;
                    }
                }
                comp.minOnline = newMin;
            }
        }
    }

    return result;
}

