#include <vector>
#include <map>
#include <algorithm>

using namespace std;

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    // DSU setup
    vector<int> parent(c + 1);
    for (int i = 0; i <= c; ++i) {
        parent[i] = i;
    }

    function<int(int)> find = [&](int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    for (const auto& conn : connections) {
        int u = conn[0];
        int v = conn[1];
        int rootU = find(u);
        int rootV = find(v);
        if (rootU != rootV) {
            parent[rootV] = rootU;
        }
    }

    // Group nodes by root
    map<int, vector<int>> componentNodes;
    for (int node = 1; node <= c; ++node) {
        int root = find(node);
        componentNodes[root].push_back(node);
    }

    // Sort each component's nodes
    for (auto& [root, nodes] : componentNodes) {
        sort(nodes.begin(), nodes.end());
    }

    // Online status
    vector<bool> online(c + 1, true);

    // Process queries
    vector<long long> result;

    for (const auto& q : queries) {
        int type = q[0];
        int x = q[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                int root = find(x);
                int minOnline = -1;
                for (int node : componentNodes[root]) {
                    if (online[node]) {
                        minOnline = node;
                        break;
                    }
                }
                result.push_back(minOnline);
            }
        } else {
            // type 2: offline
            online[x] = false;
        }
    }

    return result;
}
