#include <vector>
#include <map>
#include <algorithm>

using namespace std;

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    vector<int> parent(c + 1);
    vector<int> rank(c + 1, 0);
    for (int i = 0; i <= c; ++i) {
        parent[i] = i;
    }

    auto find = [&](int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    for (const auto& conn : connections) {
        int u = conn[0];
        int v = conn[1];
        int rootU = find(u);
        int rootV = find(v);
        if (rootU != rootV) {
            if (rank[rootU] < rank[rootV]) {
                parent[rootU] = rootV;
            } else {
                parent[rootV] = rootU;
                if (rank[rootU] == rank[rootV]) {
                    rank[rootU]++;
                }
            }
        }
    }

    map<int, vector<int>> components;
    for (int node = 1; node <= c; ++node) {
        int root = find(node);
        components[root].push_back(node);
    }

    for (auto& [root, nodes] : components) {
        sort(nodes.begin(), nodes.end());
    }

    map<int, pair<vector<int>, int>> componentData;
    for (auto& [root, nodes] : components) {
        componentData[root] = { nodes, nodes[0] };
    }

    vector<bool> online(c + 1, true);

    vector<long long> result;

    for (const auto& query : queries) {
        int type = query[0];
        int x = query[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                int root = find(x);
                auto& comp = componentData[root];
                if (comp.second != -1) {
                    result.push_back(comp.second);
                } else {
                    result.push_back(-1);
                }
            }
        } else {
            online[x] = false;
            int root = find(x);
            auto& comp = componentData[root];
            if (comp.second == x) {
                int new_min = -1;
                for (int node : comp.first) {
                    if (online[node]) {
                        new_min = node;
                        break;
                    }
                }
                comp.second = new_min;
            }
        }
    }

    return result;
}
