#include <vector>
#include <map>
#include <algorithm>

using namespace std;

struct DSU {
    vector<int> parent;
    vector<int> rank;
    DSU(int n) : parent(n+1), rank(n+1, 0) {
        for (int i = 0; i <= n; ++i) {
            parent[i] = i;
            rank[i] = 1;
        }
    }
    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
    void union_(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);
        if (rootX != rootY) {
            if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else {
                parent[rootY] = rootX;
                if (rank[rootX] == rank[rootY]) {
                    rank[rootX]++;
                }
            }
        }
    }
};

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    DSU dsu(c);
    for (const auto& conn : connections) {
        long long u = conn[0];
        long long v = conn[1];
        dsu.union_(u, v);
    }

    map<long long, pair<vector<long long>, long long>> componentData;
    for (long long node = 1; node <= c; ++node) {
        long long root = dsu.find(node);
        if (componentData.find(root) == componentData.end()) {
            componentData[root] = { {node}, node };
        } else {
            componentData[root].first.push_back(node);
        }
    }

    for (auto& [root, data] : componentData) {
        sort(data.first.begin(), data.first.end());
        data.second = data.first[0];
    }

    vector<bool> online(c + 1, true);
    vector<long long> result;

    for (const auto& q : queries) {
        long long type = q[0];
        long long x = q[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                long long root = dsu.find(x);
                auto& comp = componentData[root];
                if (comp.second != -1) {
                    result.push_back(comp.second);
                } else {
                    result.push_back(-1);
                }
            }
        } else {
            online[x] = false;
            long long root = dsu.find(x);
            auto& comp = componentData[root];
            if (comp.second == x) {
                long long newMin = -1;
                for (long long node : comp.first) {
                    if (online[node]) {
                        newMin = node;
                        break;
                    }
                }
                comp.second = newMin;
            }
        }
    }

    return result;
}
